    }, []);

    const baseCardClass = "bg-[rgba(255,255,255,0.7)] backdrop-blur-[12px] rounded-[24px] border border-[rgba(255,255,255,0.4)] shadow-[0_8px_32px_rgba(0,0,0,0.05)] p-6 mb-8";
